parameters.jsCode:
const full = $input.first().json;
const body = full.body || full;
const message = body.message || {};
const toolCalls = message.toolCalls || message.toolCallList || [];
const firstTool = toolCalls[0] || {};

// arguments comes as a JSON string, must be parsed
const raw = firstTool.function?.arguments || "{}";
const data = typeof raw === "string" ? JSON.parse(raw) : raw;

return [{
  json: {
    timestamp: new Date().toISOString(),
    callType: data.callType || "General Enquiry",
    callerName: data.callerName || "Unknown",
    callerPhone: data.callerPhone || "Unknown",
    orderDetails: Array.isArray(data.orderDetails)
      ? data.orderDetails.map(i =>
          `${i.quantity}x ${i.item}${i.size ? " (" + i.size + ")" : ""}${i.protein ? " + " + i.protein : ""}`
        ).join(", ")
      : data.orderDetails || "",
    deliveryOrPickup: data.deliveryOrPickup || "",
    deliveryAddress: data.deliveryAddress || "",
    reservationDate: data.reservationDate || "",
    reservationTime: data.reservationTime || "",
    partySize: data.partySize || "",
    escalationReason: data.escalationReason || "",
    totalEstimate: data.totalEstimate
      ? "₦" + Number(data.totalEstimate).toLocaleString()
      : "",
    questionAsked: data.questionAsked || "",
    answerProvided: data.answerProvided || ""
  }
}];

